consumption.cssSetup:
Import tokens CSS at your app entry point: import '@ds-mo/tokens/css';
This provides all var(--color-*), var(--dimension-*), var(--effect-*), and var(--typography-*) custom properties.
For dark mode, set data-theme="dark" on <html>.

files.content:
/**
 * Card — structured container with optional header/footer.
 * Uses TokoMo tokens directly (not built on Surface).
 */

.card {
  box-sizing: border-box;
  background-color: var(--color-background-primary);
  overflow: hidden;
}

/* Elevation */
.elevationFlat { box-shadow: var(--effect-elevation-elevated-none); }
.elevationElevated { box-shadow: var(--effect-elevation-elevated-sm); }
.elevationFloating { box-shadow: var(--effect-elevation-elevated-floating); }

/* Radius */
.radiusSm { border-radius: var(--dimension-radius-075); }
.radiusMd { border-radius: var(--dimension-radius-100); }
.radiusLg { border-radius: var(--dimension-radius-125); }
.radiusXl { border-radius: var(--dimension-radius-175); }

/* Sections */
.header {
  padding: var(--dimension-space-150) var(--dimension-space-200);
  border-bottom: var(--dimension-stroke-width-015) solid var(--color-border-primary);
}

.body {
  padding: var(--dimension-space-200);
}

.footer {
  padding: var(--dimension-space-150) var(--dimension-space-200);
  border-top: var(--dimension-stroke-width-015) solid var(--color-border-primary);
}

import React, { forwardRef } from 'react';
import styles from './Card.module.css';
import { cn } from '@/utils/cn';

export type CardElevation = 'flat' | 'elevated' | 'floating';
export type CardRadius = 'sm' | 'md' | 'lg' | 'xl';

export interface CardProps {
  children: React.ReactNode;
  /** Optional header content — rendered with a bottom divider. */
  header?: React.ReactNode;
  /** Optional footer content — rendered with a top divider. */
  footer?: React.ReactNode;
  /** Elevation level. Defaults to 'elevated'. */
  elevation?: CardElevation;
  /** Corner radius. Defaults to 'lg'. */
  radius?: CardRadius;
  /** Additional CSS classes. */
  className?: string;
  /** Inline styles. */
  style?: React.CSSProperties;
}

const elevationClassMap: Record<CardElevation, string> = {
  flat: styles.elevationFlat,
  elevated: styles.elevationElevated,
  floating: styles.elevationFloating,
};

const radiusClassMap: Record<CardRadius, string> = {
  sm: styles.radiusSm,
  md: styles.radiusMd,
  lg: styles.radiusLg,
  xl: styles.radiusXl,
};

export const Card = forwardRef<HTMLDivElement, CardProps>(
  ({ children, header, footer, elevation = 'elevated', radius = 'lg', className, style }, ref) => {
    return (
      <div
        ref={ref}
        className={cn(styles.card, elevationClassMap[elevation], radiusClassMap[radius], className)}
        style={style}
      >
        {header && <div className={styles.header}>{header}</div>}
        <div className={styles.body}>{children}</div>
        {footer && <div className={styles.footer}>{footer}</div>}
      </div>
    );
  }
);

Card.displayName = 'Card';
